//! Parity test: compare Stemma redlines against Microsoft Word redlines.
//!
//! For every sample that has both `word_redline.docx` (generated by Word's
//! Compare Documents) and a before/after pair, this test:
//!
//! 1. Generates a fresh `stemma_redline.docx` via the diff+redline pipeline
//! 2. Extracts accept-all / reject-all text from both DOCX files
//! 3. Asserts they match (after whitespace normalization)
//!
//! This ensures our tracked-change markup produces the same document text
//! as Word's tracked-change markup when changes are accepted or rejected.
//!
//! Run via: `just redline-word-parity`

use std::fs;

use stemma::redline_extract::{RedlineParagraph, extract_redline};
use stemma::{DocxRuntime, ExportMode, SimpleRuntime, TransactionMeta};

mod common;

// ── helpers ──────────────────────────────────────────────────────────────

fn redline_meta() -> TransactionMeta {
    TransactionMeta {
        author: "Stemma".to_string(),
        reason: None,
        timestamp_utc: Some("2025-01-15T10:30:00Z".to_string()),
    }
}

fn generate_stemma_redline(before_path: &str, after_path: &str) -> Vec<u8> {
    let runtime = SimpleRuntime::new();

    let before_bytes =
        fs::read(before_path).unwrap_or_else(|err| panic!("read {before_path}: {err}"));
    let after_bytes = fs::read(after_path).unwrap_or_else(|err| panic!("read {after_path}: {err}"));

    let import_before = runtime
        .import_docx(&before_bytes)
        .unwrap_or_else(|err| panic!("import {before_path}: {err:?}"));
    let import_after = runtime
        .import_docx(&after_bytes)
        .unwrap_or_else(|err| panic!("import {after_path}: {err:?}"));

    let apply = runtime
        .diff_and_redline(
            &import_before.doc_handle,
            &import_after.doc_handle,
            redline_meta(),
        )
        .unwrap_or_else(|err| panic!("diff_and_redline: {err:?}"));
    assert!(apply.applied, "redline must produce changes");

    runtime
        .export_docx(&import_before.doc_handle, ExportMode::Redline)
        .unwrap_or_else(|err| panic!("export_docx: {err:?}"))
}

fn extract_accept_text(paragraphs: &[RedlineParagraph]) -> String {
    normalize_doc_text(
        &paragraphs
            .iter()
            .map(|p| p.accept_text())
            .collect::<Vec<_>>(),
    )
}

fn extract_reject_text(paragraphs: &[RedlineParagraph]) -> String {
    normalize_doc_text(
        &paragraphs
            .iter()
            .map(|p| p.reject_text())
            .collect::<Vec<_>>(),
    )
}

/// Normalize for whole-document text comparison.
/// Joins all paragraphs and collapses whitespace so paragraph boundaries
/// don't affect the comparison — only text content matters.
fn normalize_doc_text(para_texts: &[String]) -> String {
    let combined = para_texts.join(" ");
    combined.split_whitespace().collect::<Vec<_>>().join(" ")
}

/// Discover samples in `../backend/samples/` that have both `word_redline.docx`
/// and before/after pairs.
fn discover_word_parity_fixtures() -> Vec<(String, String, String, String)> {
    let samples_dir = common::samples_dir();
    let mut fixtures = Vec::new();

    let entries = match fs::read_dir(&samples_dir) {
        Ok(e) => e,
        Err(_) => return fixtures,
    };

    for entry in entries.flatten() {
        let path = entry.path();
        if !path.is_dir() {
            continue;
        }

        let name = path.file_name().unwrap().to_string_lossy().to_string();
        let before = path.join("before.docx");
        let after = path.join("after.docx");
        let word_redline = path.join("word_redline.docx");

        if before.exists() && after.exists() && word_redline.exists() {
            fixtures.push((
                name,
                before.to_string_lossy().to_string(),
                after.to_string_lossy().to_string(),
                word_redline.to_string_lossy().to_string(),
            ));
        }
    }

    fixtures.sort_by(|a, b| a.0.cmp(&b.0));
    fixtures
}

fn fixture_filter() -> Option<String> {
    match std::env::var("WORD_PARITY_FIXTURE") {
        Ok(raw) => {
            let trimmed = raw.trim().to_string();
            if trimmed.is_empty() {
                None
            } else {
                Some(trimmed)
            }
        }
        Err(std::env::VarError::NotPresent) => None,
        Err(err) => panic!("failed to read WORD_PARITY_FIXTURE: {err}"),
    }
}

// ── exclusions ───────────────────────────────────────────────────────────

/// Known Word-parity failures, documented but **not skipped**.
///
/// This list exists purely for documentation. The test runs every fixture
/// and is expected to fail until these are fixed.
///
/// ## Previously fixed (removed from list)
/// - RC1 ordering tests (ordering-delete-around-middle, ordering-mixed-complex,
///   ordering-multi-insert, math-wc021): fixed by paragraph mark annotation improvements.
/// - RC2 math structural inversion (math-equations, image-math-combined): fixed by
///   `apply_deep_math_tracking` placing tracking inside `m:r`/`m:ctrlPr`.
/// - RC3 math paragraph boundary (image-math-wc030): fixed by
///   `paragraph_has_content_inlines` guard in `is_wholly_paragraph_opaque_change`.
/// - RC4 opaque serialization ordering (opaque-roundtrip): fixed by FFFC strong
///   anchor in zipper collapse + fldSimple extraction normalization.
/// - RC6 math font contamination (image-math-combined): fixed by
///   `is_wholly_paragraph_opaque_change` guard fix (38e2bf1d).
///
/// ## RC1b: Paragraph split serialization + hyperlink projection (5 SAFE + humira-epar)
/// Two overlapping causes:
/// 1. **Paragraph splits**: Word emits 2 `<w:p>` with `para_mark_status = Inserted`;
///    Stemma emits 1 `<w:p>` with inline changes + 1 wholly-inserted `<w:p>`.
///    The `para_split` flag and `reconcile_paragraph_splits()` detection exist
///    but the serializer doesn't act on them yet.
/// 2. **Hyperlink text projection**: Word's redline converts `w:hyperlink` to
///    `fldChar` triplets, exposing display text in the extract. Stemma preserves
///    `w:hyperlink` as opaque (single FFFC), dropping display text.
///    `humira-epar` additionally has a large paragraph count mismatch (2385 fewer
///    paragraphs in Stemma) due to alignment differences at scale.
///
/// Fixtures excluded from the failure assertion. These are documented design
/// choices where Stemma intentionally diverges from Word's behavior.
/// They still run and report, but don't count as failures.
const DESIGN_CHOICE_DIVERGENCES: &[&str] = &[
    // RC5: Stemma normalizes pre-existing tracked changes before diffing.
    "preexisting-tracked-changes",
];

#[allow(dead_code)]
const WORD_PARITY_KNOWN_FAILURES: &[&str] = &[
    // RC1b: paragraph split serialization + hyperlink text projection
    "safe-valcap-vs-discount",
    "safe-valcap-vs-mfn",
    "safe-us-vs-canada",
    "safe-us-vs-cayman",
    "safe-us-vs-singapore",
    // RC1b + large document alignment
    "humira-epar",
];

// ── test ─────────────────────────────────────────────────────────────────

/// For every sample with a `word_redline.docx`, verify that:
/// - `accept(stemma_redline) == accept(word_redline)`
/// - `reject(stemma_redline) == reject(word_redline)`
///
/// This is a content-level parity check: both redlines should produce
/// the same document text when all changes are accepted or rejected.
///
/// No fixtures are excluded — all failures are reported. See
/// `WORD_PARITY_KNOWN_FAILURES` for documented categories of differences.
#[test]
#[ignore = "nightly — generates redlines for all samples with word_redline.docx"]
fn word_parity_accept_reject() {
    let fixtures = discover_word_parity_fixtures();
    assert!(!fixtures.is_empty(), "no word-parity fixtures found");

    let filter = fixture_filter();

    let mut checked = 0usize;
    let mut failures = Vec::new();
    let mut divergences = Vec::new();

    for (name, before_path, after_path, word_redline_path) in &fixtures {
        if let Some(ref f) = filter
            && name != f
            && !name.contains(f.as_str())
        {
            continue;
        }

        eprint!("  {name}... ");

        // Extract Word redline
        let word_bytes = fs::read(word_redline_path)
            .unwrap_or_else(|err| panic!("[{name}] read word_redline: {err}"));
        let word_extract = extract_redline(&word_bytes)
            .unwrap_or_else(|err| panic!("[{name}] extract word_redline: {err}"));

        // Generate and extract Stemma redline
        let stemma_bytes = generate_stemma_redline(before_path, after_path);
        let stemma_extract = extract_redline(&stemma_bytes)
            .unwrap_or_else(|err| panic!("[{name}] extract stemma_redline: {err}"));

        // Compare accept-all views
        let word_accept = extract_accept_text(&word_extract.body);
        let stemma_accept = extract_accept_text(&stemma_extract.body);

        // Compare reject-all views
        let word_reject = extract_reject_text(&word_extract.body);
        let stemma_reject = extract_reject_text(&stemma_extract.body);

        let accept_match = word_accept == stemma_accept;
        let reject_match = word_reject == stemma_reject;

        if accept_match && reject_match {
            eprintln!("OK");
        } else {
            let mut detail = String::new();
            if !accept_match {
                detail.push_str(&format!(
                    "accept-all mismatch:\n  word:    {}\n  stemma: {}\n",
                    truncate(&word_accept, 200),
                    truncate(&stemma_accept, 200),
                ));
            }
            if !reject_match {
                detail.push_str(&format!(
                    "reject-all mismatch:\n  word:    {}\n  stemma: {}\n",
                    truncate(&word_reject, 200),
                    truncate(&stemma_reject, 200),
                ));
            }

            let is_design_choice = DESIGN_CHOICE_DIVERGENCES.contains(&name.as_str());
            if is_design_choice {
                eprintln!("DIVERGENCE (design choice)");
                divergences.push((name.clone(), detail));
            } else {
                eprintln!("FAIL");
                failures.push((name.clone(), detail));
            }
        }

        checked += 1;
    }

    eprintln!(
        "\nword parity: {} checked, {} failures, {} design-choice divergences, filter={:?}",
        checked,
        failures.len(),
        divergences.len(),
        filter,
    );

    if !divergences.is_empty() {
        eprintln!("\nDesign-choice divergences (not counted as failures):");
        for (name, _) in &divergences {
            eprintln!("  {name}");
        }
    }

    if !failures.is_empty() {
        let mut msg = format!("{} fixture(s) failed word parity:\n\n", failures.len());
        for (name, detail) in &failures {
            msg.push_str(&format!("--- {name} ---\n{detail}\n"));
        }
        panic!("{msg}");
    }

    assert!(checked > 0, "expected at least one fixture to be checked");
}

fn truncate(s: &str, max: usize) -> String {
    if s.len() <= max {
        s.to_string()
    } else {
        format!("{}...", &s[..max])
    }
}
